-- ═══════════════════════════════════════════════════════════════════════════
-- articles_v1.sql
--
-- سياق: Phase 10 من التكليف الأصلي ("مقالات أصلية جديدة") — **لم تكن له
-- أي بنية تحتية فعلية**. تحقّقتُ أولاً: `CmsContentKind` يضم "article" كنوع
-- محتوى في content-registry.ts، لكن مُعرَّف بـ`table: "library_items"`
-- (جدول DB شبه فارغ لا يُستهلَك في أي صفحة عرض حقيقية — نفس نمط بقايا
-- fatwa اليتيمة المُكتشَفة سابقاً هذه الجلسات) و`publicRoute: () =>
-- "/library"` (لا يوجد مسار `/articles` أو صفحة عرض مقال إطلاقاً في
-- src/App.tsx). أي كتابة مقال حقيقي عبر هذا المسار كانت ستُنتج سجلاً
-- يتيماً تماماً بلا أي عرض علني ممكن — تكرار لنفس الخطأ الذي أُصلح جزئياً
-- في KnowledgeSourceType سابقاً.
--
-- القرار: **جدول جديد بسيط `articles`**، مستقل تماماً عن content-registry
-- المكسور، بنفس نمط `is_approved`/`verified_by`/`approved_at` المستخدَم
-- فعلاً في `islamic_stories`/`prophet_stories` (نمط مثبَت في المشروع).
-- **لم يُبنَ مسار/صفحة عرض علنية `/articles/:slug` في هذه الدفعة عمداً**
-- — بناء صفحة جديدة عمل واجهة/تصميم كامل (خارج نطاق "مقالة نموذج واحدة
-- كإثبات نمط"، ويخالف توجيه "تجنّب عمل الواجهة/نظام التصميم" الثابت لهذا
-- الوكيل). حالة `is_approved=false` + غياب أي مسار عرض = تمثيل صادق تماماً
-- لـ"محتوى قيد المراجعة، غير منشور بعد" — لا خطر عرض مطلقاً، بلا حاجة
-- لصفحة لإثبات ذلك.
--
-- المقالة النموذج: "أركان الإيمان الستة: تعريفها وأدلتها من القرآن
-- والسنة" — تُعيد استخدام مادة مُتحقَّقة بالفعل هذه الجلسات (لا استشهاد
-- جديد غير مُتحقَّق): آيات مستخرَجة حرفياً من public/data/quran/surah-*.json
-- (النساء:136، البقرة:285، البقرة:177، القمر:49)، حديث جبريل (مسلم 8،
-- البخاري 50، الأربعين النووية 2) من مقرر arkan-al-iman المبني سابقاً.
-- إضافة جديدة واحدة تحقّقت هذه الدفعة عبر WebSearch: تعريف الإيمان عند
-- أهل السنة (قول باللسان + اعتقاد بالقلب + عمل بالجوارح، يزيد وينقص)
-- مقابل موقف المرجئة (الأعمال ليست داخلة في مسمى الإيمان) — خلاف عقدي
-- حقيقي مشهور، عُرض بأمانة بذكر الموقفين دون فتوى شخصية، مع ترجيح موقف
-- أهل السنة كموقف الأغلبية الساحقة من علماء الإسلام عبر التاريخ (لا
-- ترجيح شخصي مبتدَع، بل نقل إجماع تاريخي موثَّق).
--
-- روابط داخلية مضمَّنة في body تشير إلى محتوى حقيقي بُني فعلاً هذه
-- الجلسات: /learning/paths/aqeedah (مقرر أركان الإيمان)، /arkan-iman
-- (الصفحة المرجعية المستقلة الموجودة مسبقاً)، /library/book-luma-itiqad-
-- ibn-qudama (لمعة الاعتقاد).
-- ═══════════════════════════════════════════════════════════════════════════

CREATE TABLE IF NOT EXISTS articles (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  slug text UNIQUE NOT NULL,
  title text NOT NULL,
  subtitle text,
  summary text NOT NULL,
  body text NOT NULL,
  category text NOT NULL,
  tags jsonb NOT NULL DEFAULT '[]'::jsonb,
  sources jsonb NOT NULL DEFAULT '[]'::jsonb,
  related_links jsonb NOT NULL DEFAULT '[]'::jsonb,
  faq jsonb NOT NULL DEFAULT '[]'::jsonb,
  is_approved boolean NOT NULL DEFAULT false,
  verified_by text,
  approved_at timestamptz,
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now()
);

COMMENT ON TABLE articles IS
  'مقالات أصلية طويلة (Phase 10). جدول جديد مستقل عن content-registry '
  '(الذي يشير خطأً لـlibrary_items بلا صفحة عرض). is_approved=false '
  'افتراضياً لكل مقالة جديدة — لا نشر تلقائي. لا صفحة/مسار عرض علني بعد '
  '(قرار متعمَّد لتفادي عمل واجهة كامل خارج نطاق هذه الدفعة).';

ALTER TABLE articles ENABLE ROW LEVEL SECURITY;

-- قراءة عامة فقط للمقالات المعتمدة فعلاً (نفس نمط الحماية المستخدَم في
-- verified_hadith_items وislamic_stories — لا اعتماد = لا ظهور عام أبداً،
-- حتى لو بُنيت صفحة عرض مستقبلاً بلا تعديل هذه السياسة).
DROP POLICY IF EXISTS articles_public_read ON articles;
CREATE POLICY articles_public_read ON articles
  FOR SELECT
  USING (is_approved = true);

INSERT INTO articles (slug, title, subtitle, summary, body, category, tags, sources, related_links, faq, is_approved)
VALUES (
  'arkan-al-iman-al-sitta',
  'أركان الإيمان الستة: تعريفها وأدلتها من القرآن والسنة',
  'دليل شامل لأركان الإيمان الستة كما وردت في حديث جبريل عليه السلام، بأدلتها من القرآن الكريم والسنة الصحيحة',
  'شرح مفصَّل لأركان الإيمان الستة (بالله، وملائكته، وكتبه، ورسله، واليوم الآخر، والقدر خيره وشره) بأدلة قرآنية وحديثية مُخرَّجة، مع بيان خلاف علمي حقيقي حول علاقة العمل بمسمى الإيمان، وروابط لمصادر تعليمية أعمق على المنصة.',
  E'## مقدمة\n\nأركان الإيمان الستة هي الأصل الذي يقوم عليه الاعتقاد الإسلامي كله. لم تُستنبَط هذه الأركان اجتهاداً من العلماء، بل نصّ عليها النبي ﷺ نصّاً صريحاً في حديث واحد جامع يُعرَف بـ"حديث جبريل". هذا المقال يعرض الأركان الستة بأدلتها، ثم يوضّح مسألة خلافية مشهورة تتعلق بتعريف الإيمان ذاته، مع تمييز واضح بين ما هو نصّ قطعي وما هو صياغة علمية أو تنظيم عرض.\n\n## الأصل: حديث جبريل عليه السلام\n\nسأل جبريلُ عليه السلام النبيَّ ﷺ عن الإيمان، فقال ﷺ: «أن تؤمن بالله وملائكته وكتبه ورسله واليوم الآخر، وتؤمن بالقدر خيره وشره» — رواه الإمام مسلم في صحيحه، كتاب الإيمان، حديث رقم 8، من حديث عمر بن الخطاب رضي الله عنه، وأصله في صحيح البخاري، حديث رقم 50، من حديث أبي هريرة رضي الله عنه بلفظ قريب، وهو الحديث الثاني في الأربعين النووية.\n\n**هذا نصّ قطعي الثبوت** (صحيح متفق عليه)، وهو الأصل الذي بُنيت عليه كل الأركان الستة أدناه — لا اجتهاد بشري في عددها أو أصل مضمونها.\n\n## الركن الأول: الإيمان بالله\n\nالتصديق الجازم بوجود الله سبحانه، وتوحيده في ربوبيته وألوهيته وأسمائه وصفاته. قال تعالى: ﴿يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ ءَامِنُوا۟ بِٱللَّهِ وَرَسُولِهِۦ وَٱلْكِتَٰبِ ٱلَّذِى نَزَّلَ عَلَىٰ رَسُولِهِۦ وَٱلْكِتَٰبِ ٱلَّذِىٓ أَنزَلَ مِن قَبْلُ﴾ (سورة النساء: 136).\n\n## الركن الثاني: الإيمان بالملائكة\n\nالتصديق بوجودهم، وأنهم خلق من نور مكرَّمون لا يعصون الله ما أمرهم. قال تعالى: ﴿ءَامَنَ ٱلرَّسُولُ بِمَآ أُنزِلَ إِلَيْهِ مِن رَّبِّهِۦ وَٱلْمُؤْمِنُونَ ۚ كُلٌّ ءَامَنَ بِٱللَّهِ وَمَلَٰٓئِكَتِهِۦ وَكُتُبِهِۦ وَرُسُلِهِۦ﴾ (سورة البقرة: 285).\n\n## الركن الثالث: الإيمان بالكتب\n\nالتصديق بأن الله أنزل على أنبيائه كتباً فيها هداه، وأن القرآن آخرها وناسخها والمهيمن عليها، المحفوظ من التبديل بخلاف ما سبقه. قال تعالى: ﴿وَٱلْكِتَٰبِ ٱلَّذِى نَزَّلَ عَلَىٰ رَسُولِهِۦ وَٱلْكِتَٰبِ ٱلَّذِىٓ أَنزَلَ مِن قَبْلُ﴾ (سورة النساء: 136، جزء من الآية السابقة).\n\n## الركن الرابع: الإيمان بالرسل\n\nالتصديق بأن الله أرسل إلى كل أمة رسولاً، وأن محمداً ﷺ خاتمهم، ووجوب الإيمان بهم جميعاً دون تفريق. قال تعالى: ﴿لَا نُفَرِّقُ بَيْنَ أَحَدٍۢ مِّن رُّسُلِهِۦ﴾ (سورة البقرة: 285، جزء من الآية السابقة).\n\n## الركن الخامس: الإيمان باليوم الآخر\n\nالتصديق بكل ما أخبر الله به ورسوله ﷺ مما يكون بعد الموت: البعث، والحساب، والجنة والنار. قال تعالى: ﴿لَّيْسَ ٱلْبِرَّ أَن تُوَلُّوا۟ وُجُوهَكُمْ قِبَلَ ٱلْمَشْرِقِ وَٱلْمَغْرِبِ وَلَٰكِنَّ ٱلْبِرَّ مَنْ ءَامَنَ بِٱللَّهِ وَٱلْيَوْمِ ٱلْءَاخِرِ وَٱلْمَلَٰٓئِكَةِ وَٱلْكِتَٰبِ وَٱلنَّبِيِّۦنَ﴾ (سورة البقرة: 177).\n\n## الركن السادس: الإيمان بالقدر خيره وشره\n\nالتصديق بأن الله علم مقادير الأشياء أزلاً وكتبها وشاءها وخلقها، مع إثبات مشيئة واختيار حقيقيين للعبد يُحاسَب عليهما. قال تعالى: ﴿إِنَّا كُلَّ شَىْءٍ خَلَقْنَٰهُ بِقَدَرٍۭ﴾ (سورة القمر: 49).\n\n## مسألة خلافية بأمانة: هل العمل داخل في مسمى الإيمان؟\n\nحديث جبريل يُعرِّف الإيمان بالتصديق القلبي (أن تؤمن بكذا وكذا) دون ذكر صريح للعمل فيه. هذا فتح باباً لخلاف عقدي مشهور بين طوائف المسلمين حول تعريف "الإيمان" ذاته — **هذه المسألة اجتهادية عند من قال بها لا نصّية قطعية كأصل الأركان الستة نفسها**:\n\n- **موقف أهل السنة والجماعة** (وهو موقف جمهور علماء الإسلام عبر التاريخ): الإيمان "قول باللسان، واعتقاد بالقلب، وعمل بالجوارح"، يزيد بالطاعة وينقص بالمعصية. عليه فالأعمال الظاهرة (كالصلاة والزكاة) جزء من حقيقة الإيمان لا مجرد ثمرة له.\n- **موقف المرجئة**: الأعمال ليست داخلة في مسمى الإيمان أصلاً، بل الإيمان تصديق القلب (أو تصديق مع نطق اللسان) فقط، والعمل خارج عن حقيقته.\n\nهذا خلاف عقدي حقيقي موثَّق في كتب الفرق والعقائد، لا رأياً شخصياً يطرحه هذا المقال؛ وموقف أهل السنة هو موقف الأغلبية الساحقة من علماء الإسلام عبر القرون، لا ترجيحاً مبتدَعاً هنا.\n\n## أركان الإيمان مقابل أركان الإسلام: تمييز ضروري\n\nيخلط بعض المبتدئين بين "أركان الإيمان" (الستة أعلاه، اعتقادية) و"أركان الإسلام" (الشهادتان والصلاة والزكاة والصوم والحج، عملية). كلاهما وردا في حديث جبريل نفسه لكن في سؤالين منفصلين ("ما الإيمان؟" و"ما الإسلام؟") — وهذا فرق نصّي واضح لا خلاف فيه بين العلماء.\n\n## تعمَّق أكثر على المنصة\n\nهذا المقال مدخل مختصر. لدراسة كل ركن بتفصيل أوسع (تمهيد، دليل لكل ركن، ربط بكتاب "لمعة الاعتقاد" لابن قدامة) راجع مقرر "أركان الإيمان الستة" ضمن [مسار العقيدة التعليمي](/learning/paths/aqeedah)، أو الصفحة المرجعية التفاعلية [أركان الإيمان](/arkan-iman) لعرض تفصيلي لكل ركن بأدلته وتفاصيله الفقهية والعقدية، أو راجع كتاب [لمعة الاعتقاد الهادي إلى سبيل الرشاد](/library/book-luma-itiqad-ibn-qudama) لابن قدامة المقدسي مباشرة في مكتبة المنصة.\n\n## خلاصة\n\nأركان الإيمان الستة نصّ قطعي ثابت بحديث جبريل الصحيح المتفق عليه، ولكل ركن دليل قرآني صريح مستقل. أما مسألة دخول العمل في مسمى الإيمان فخلاف عقدي معروف بين أهل السنة والمرجئة، عُرض هنا بأمانة دون فتوى شخصية.',
  'عقيدة',
  '["أركان الإيمان", "عقيدة", "حديث جبريل", "أهل السنة", "المرجئة"]'::jsonb,
  '["صحيح مسلم، كتاب الإيمان، حديث رقم 8", "صحيح البخاري، حديث رقم 50", "الأربعون النووية، الحديث الثاني", "سورة النساء: 136", "سورة البقرة: 285", "سورة البقرة: 177", "سورة القمر: 49"]'::jsonb,
  '[{"label": "مقرر أركان الإيمان الستة — مسار العقيدة", "url": "/learning/paths/aqeedah"}, {"label": "أركان الإيمان — صفحة مرجعية تفاعلية", "url": "/arkan-iman"}, {"label": "لمعة الاعتقاد الهادي إلى سبيل الرشاد — المكتبة", "url": "/library/book-luma-itiqad-ibn-qudama"}]'::jsonb,
  '[{"question": "هل أركان الإيمان الستة محل اتفاق بين كل المسلمين؟", "answer": "نعم، أصل الأركان الستة وعددها ثابت بنصّ حديث جبريل الصحيح المتفق عليه بين البخاري ومسلم، ولا خلاف بين المسلمين في عددها أو أصل مضمونها."}, {"question": "هل يكفي الإيمان القلبي وحده دون عمل؟", "answer": "هذه مسألة خلافية بين المذاهب العقدية كما وُضِّح في المقال: أهل السنة والجماعة (جمهور العلماء) يرون أن العمل جزء من حقيقة الإيمان لا مجرد ثمرة له، بخلاف المرجئة الذين يُخرِجون العمل من مسمى الإيمان."}, {"question": "ما الفرق بين أركان الإيمان وأركان الإسلام؟", "answer": "أركان الإيمان الستة اعتقادية قلبية (الإيمان بالله والملائكة والكتب والرسل واليوم الآخر والقدر)، بينما أركان الإسلام الخمسة عملية ظاهرة (الشهادتان والصلاة والزكاة والصوم والحج). كلاهما ورد في حديث جبريل نفسه في سؤالين منفصلين."}]'::jsonb,
  false
)
ON CONFLICT (slug) DO NOTHING;
